# Source: https://leetcode.com/problems/find-the-key-of-the-numbers/   |   Difficulty: Easy
#
# Problem Description:
# You are given three positive integers num1, num2, and num3.
#
# The key of num1, num2, and num3 is defined as a four-digit number such that:
#
#
# 	Initially, if any number has less than four digits, it is padded with leading zeros.
# 	The ith digit (1 <= i <= 4) of the key is generated by taking the smallest digit among the ith digits of num1, num2, and num3.
#
#
# Return the key of the three numbers without leading zeros (if any).
#
# Example:
# Input: num1 = 1, num2 = 10, num3 = 1000
#
# Output: 0
#
# Explanation:
#
# On padding, num1 becomes "0001", num2 becomes "0010", and num3 remains "1000".
#
#
# 	The 1st digit of the key is min(0, 0, 1).
# 	The 2nd digit of the key is min(0, 0, 0).
# 	The 3rd digit of the key is min(0, 1, 0).
# 	The 4th digit of the key is min(1, 0, 0).
#
#
# Hence, the key is "0000", i.e. 0.
#
# Constraints:
# 1 <= num1, num2, num3 <= 9999
#

class Solution(object):
    def generateKey(self, num1, num2, num3):
        """
        :type num1: int
        :type num2: int
        :type num3: int
        :rtype: int
        """
        str1 = str(num1).zfill(4)
        str2 = str(num2).zfill(4)
        str3 = str(num3).zfill(4)
        
        key_digits = []
        for i in range(4):
            min_digit = min(str1[i], str2[i], str3[i])
            key_digits.append(min_digit)
        
        key_str = ''.join(key_digits)
        return int(key_str)